class Solution:
    def merge(self, intervals):
        pts = sorted(intervals)
        res = []
        for s, e in pts:
            if res and s <= res[-1][1]:
                if e > res[-1][1]:
                    res[-1][1] = e
            else:
                res.append([s, e])
        return res

