class Solution:
    def merge(self, intervals):
        intervals.sort(key=lambda iv: iv[0])
        res = []
        for s, e in intervals:
            if res and s <= res[-1][1]:
                res[-1][1] = max(res[-1][1], e)
            else:
                res.append([s, e])
        return res

